// 3. PROVIDER CLASS
// ---------------------------------------------------------------

export class OllamaProvider implements IEmbeddingProvider {
  modelName: string;
  dim: number;
  baseUrl: string;
  maxTextLength: number;
  timeout: number;
  isHealthy: boolean;
  requestCount: number;

  private readonly manifest: OllamaManifest;

